class CustomAuthorizationCodeServices extends InMemoryAuthorizationCodeServices {
    private final Map<String, AuthorizationCode> codes = new ConcurrentHashMap<>();
    private final ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(1);

    public CustomAuthorizationCodeServices() {
        scheduler.scheduleAtFixedRate(this::cleanupExpiredCodes, 1, 1, TimeUnit.MINUTES);
    }

    @Override
    public void addAuthorizationCode(String code, AuthorizationRequest request) {
        codes.put(code, new AuthorizationCode(code, System.currentTimeMillis() + 600000, request));
    }

    @Override
    public AuthorizationRequest removeAuthorizationCode(String code) {
        AuthorizationCode authCode = codes.remove(code);
        return authCode != null ? authCode.getRequest() : null;
    }

    private void cleanupExpiredCodes() {
        long currentTime = System.currentTimeMillis();
        codes.entrySet().removeIf(entry -> entry.getValue().getExpirationTime() < currentTime);
    }

    private static class AuthorizationCode {
        private final String code;
        private final long expirationTime;
        private final AuthorizationRequest request;

        public AuthorizationCode(String code, long expirationTime, AuthorizationRequest request) {
            this.code = code;
            this.expirationTime = expirationTime;
            this.request = request;
        }

        public String getCode() {
            return code;
        }

        public long getExpirationTime() {
            return expirationTime;
        }

        public AuthorizationRequest getRequest() {
            return request;
        }
    }
}

@RestController
class AuthorizationController {
    private final ClientDetailsService clientDetailsService;

    public AuthorizationController(ClientDetailsService clientDetailsService) {
        this.clientDetailsService = clientDetailsService;
    }

    @GetMapping("/oauth/authorize")
    public String authorize(@RequestParam Map<String, String> parameters) {
        String clientId = parameters.get("client_id");
        String redirectUri = parameters.get("redirect_uri");

        try {
            ClientDetails client = clientDetailsService.loadClientByClientId(clientId);
            if (validateRedirectUri(redirectUri, client.getRegisteredRedirectUri())) {
                return "Authorization successful";
            } else {
                return "Invalid redirect_uri";
            }
        } catch (ClientRegistrationException e) {
            return "Invalid client_id";
        }
    }

    private boolean validateRedirectUri(String redirectUri, Set<String> registeredRedirectUris) {
        if (redirectUri == null || registeredRedirectUris == null) {
            return false;
        }

        for (String registeredUri : registeredRedirectUris) {
            if (registeredUri.equals(redirectUri)) {
                return true;
            }
            if (registeredUri.endsWith("/*")) {
                String baseUri = registeredUri.substring(0, registeredUri.length() - 1);
                if (redirectUri.startsWith(baseUri)) {
                    return true;
                }
            }
        }

        return false;
    }
}